INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('generalpolice-94737317-moex-00302', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「在經過漫長的乾旱季後，雨水落在乾燥土壤上時，混雜新鮮泥土與青草的氣味， 這股聞起來令人愉悅舒爽的初雨清香，就叫——『潮土油』。潮土油一詞首次出現 在 1964 年的《自然》期刊中，由兩位澳洲的研究人員創造。該單字是由兩個希臘 字所組成：一個為『岩石、石頭』，另一個則為希臘神話中『神的血液』。科學家 進步一分析研究，構成『潮土油』的元素有：被大地吸收的植物分泌油脂，還有土 壤中的細菌，更有臭氧。」 下列選項，何者最符合詩人可以聞到「潮土油」的情境？', '["天街小雨潤如酥，草色遙看近卻無", "停車坐愛楓林晚，霜葉紅於二月花", "雨裡雞鳴一兩家，竹溪村路板橋斜", "半畝方塘一鑑開，天光雲影共徘徊"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00303', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「當人們說到『文學殿堂』時，有時會有嘲諷之意；但想到文學館，我認為它在教 化的功能上應有殿堂的莊嚴涵義，這個館應該有一個進去就吸引人的明亮的中心， 如大教堂的正廳穹蒼圓頂，或現代的展示核心，用種種聲光色電的技術，日新月異 地說明文學是什麼？圍繞著它的是臺灣文學的成績與現況，世界文學的成績與現 況，在後面是收藏、展示。它不是一個死的收藏所，而是一個活的對話！進此門來 能有一些啟發、激盪或更多的思索，至少不空心出去。」 下列選項，最符合本文意旨的是：', '["文學館應包含收藏展示，以及在地與國際的對話", "文學館的建築設計，務必要如殿堂般的富麗堂皇", "唯有聲光色電的技術，能完整呈現文學的日新月異", "「文學殿堂」一詞意義明確，單指文學的教化功能"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00304', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-13504c0c', 'sub-generalpolice-94737317-01', NULL, 'single_choice', '「真正為他人著想，絕對不是一味地執著，例如積極地想幫對方做些什麼，或是為 對方操心。即使想要表現得親切，然而受到我們自己心中煩惱的影響，可能就會做 出令對方感到困擾的事。每個人都希望自己是好人、善良的人，根據這種想法而產 生的『善良』，若是本人毫無察覺，往往就變成強加於人的一種態度。」 下列選項，最合乎本文意旨的是：', '["真正的體貼，應是積極無條件為對方付出", "為對方操心，可能演變成自己的恣意妄為", "善良的人，總是把別人的煩惱放在第一位", "只要出發點是好的，強加於人也無可厚非"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "cf19bfee6060", "answer_pdf_sha1": "e24703051873", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "0102", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(作文與測驗)", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00305', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '兩個電子各置於A、B兩點處，兩電子組成的系統電位能為U，若兩電子的位置固定不變，將另一電子 1 置於A、B的中點處，此三個電子組成的系統的總電位能為U，則U /U 為下列何者？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00306', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '2 1', '["1.5", "2", "3", "5"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00307', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一重量為W且帶電量 -q(q>0)的油滴，在均勻電場中靜止懸浮，如圖所示，則均勻電場的大小及方向為何？', '["電場為qW，且方向向上", "電場為qW，且方向向下", "電場為W/q，且方向向上", "電場為W/q，且方向向下"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00308', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '將4個5 Ω電阻串聯，並連接到20V直流電源，若將5 Ω電阻全部換成4 Ω電阻，則電源的輸出功率變 為原來的幾倍？', '["16/25倍", "4/5倍", "5/4倍", "25/16倍"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00309', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '一金屬導體製成的開口容器，底部內面裝有絕緣板。在容器外不遠處，另有一帶電物體乙與容器沒有接 觸。使帶正電的小物體甲固定於容器內的絕緣板上，則乙施給甲之靜電力的量值為F。今將一金屬導體蓋 子緊緊的蓋在容器開口上，使容器成為完全封閉的導體，則乙施給甲之靜電力的量值f為何？', '["", "", "1", "f>F f=F f= F f=0 2"]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00310', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '5個電阻與1個理想電池組合成的電路，如圖所示，則通過電池的電流為多少安培？', '["0.2", "0.5", "1.2", "2.0"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL),
  ('generalpolice-94737317-moex-00311', 'generalpolice-94737317', 'generalpolice-94737317-moex-112-9b499a9f', 'sub-generalpolice-94737317-02', NULL, 'single_choice', '由三個電容值為C 的電容器並聯所組成的電能儲存器，在汰舊換新時，新的電能儲存器換為由兩個電容值為 1 C 的電容器串聯所組成。為了使電路上其他部分的電壓不致改變，電容值C 與C 之間的關係應為何？', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:47+00:00", "source_pdf_sha1": "ed50002d2c18", "answer_pdf_sha1": "eefdb1fbfda9", "source_family": "moex-gov-tw", "moex": {"exam_code": "112070", "c": "402", "s": "1706", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "普通物理學概要與普通化學概要", "year": "112", "exam_name": "112年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "generalpolice", "civil_category": "消防警察人員"}'::jsonb, NULL)
